class RabbitMQConnection:
    def __init__(self, host: str = 'localhost', port: int = 5672, 
                 username: Optional[str] = None, password: Optional[str] = None,
                 virtual_host: str = '/', use_ssl: bool = False):
        self.host = host
        self.port = port
        self.virtual_host = virtual_host
        self.use_ssl = use_ssl
        
        # Get credentials from environment variables or use provided ones
        self.username = username or os.getenv('RABBITMQ_USERNAME', 'guest')
        self.password = password or os.getenv('RABBITMQ_PASSWORD', 'guest')
        
        # Warn if using default credentials
        if self.username == 'guest' and self.password == 'guest':
            logger.warning("Using default credentials. Please set RABBITMQ_USERNAME and RABBITMQ_PASSWORD environment variables for production use.")
        
        self.connection = None
        self.channel = None
    
    def connect(self):
        credentials = pika.PlainCredentials(self.username, self.password)
        
        parameters = pika.ConnectionParameters(
            host=self.host,
            port=self.port,
            virtual_host=self.virtual_host,
            credentials=credentials,
            heartbeat=600,
            blocked_connection_timeout=300,
            ssl_options=pika.SSLOptions() if self.use_ssl else None
        )
        
        try:
            self.connection = pika.BlockingConnection(parameters)
            self.channel = self.connection.channel()
            logger.info(f"Connected to RabbitMQ at {self.host}:{self.port}")
            return True
        except pika.exceptions.AMQPConnectionError as e:
            logger.error(f"Failed to connect to RabbitMQ: {e}")
            return False
    
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()
            logger.info("Connection to RabbitMQ closed")


class TaskPublisher:
    def __init__(self, queue_name: str = 'task_queue', 
                 host: str = 'localhost', port: int = 5672,
                 username: Optional[str] = None, password: Optional[str] = None):
        self.queue_name = queue_name
        self.rabbitmq = RabbitMQConnection(host, port, username, password)
    
    def setup(self):
        if not self.rabbitmq.connect():
            raise ConnectionError("Failed to connect to RabbitMQ")
        
        # Declare queue as durable to survive broker restarts
        self.rabbitmq.channel.queue_declare(queue=self.queue_name, durable=True)
        logger.info(f"Queue '{self.queue_name}' declared")
    
    def publish_task(self, task_data: dict):
        try:
            message = json.dumps(task_data)
            
            # Publish with persistent delivery mode
            self.rabbitmq.channel.basic_publish(
                exchange='',
                routing_key=self.queue_name,
                body=message,
                properties=pika.BasicProperties(
                    delivery_mode=2,  # Make message persistent
                    content_type='application/json'
                )
            )
            logger.info(f"Published task: {task_data}")
            return True
        except Exception as e:
            logger.error(f"Failed to publish task: {e}")
            return False
    
    def close(self):
        self.rabbitmq.close()


class TaskConsumer:
    def __init__(self, queue_name: str = 'task_queue',
                 host: str = 'localhost', port: int = 5672,
                 username: Optional[str] = None, password: Optional[str] = None,
                 prefetch_count: int = 1):
        self.queue_name = queue_name
        self.rabbitmq = RabbitMQConnection(host, port, username, password)
        self.prefetch_count = prefetch_count
        self.task_processor: Optional[Callable] = None
    
    def setup(self):
        if not self.rabbitmq.connect():
            raise ConnectionError("Failed to connect to RabbitMQ")
        
        # Declare queue as durable
        self.rabbitmq.channel.queue_declare(queue=self.queue_name, durable=True)
        
        # Set QoS to process one message at a time
        self.rabbitmq.channel.basic_qos(prefetch_count=self.prefetch_count)
        logger.info(f"Consumer setup complete for queue '{self.queue_name}'")
    
    def set_task_processor(self, processor: Callable[[dict], bool]):
        self.task_processor = processor
    
    def _callback(self, ch, method, properties, body):
        try:
            task_data = json.loads(body.decode())
            logger.info(f"Received task: {task_data}")
            
            # Process the task
            if self.task_processor:
                success = self.task_processor(task_data)
                
                if success:
                    # Acknowledge the message
                    ch.basic_ack(delivery_tag=method.delivery_tag)
                    logger.info(f"Task processed successfully: {task_data}")
                else:
                    # Reject and requeue the message
                    ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
                    logger.warning(f"Task processing failed, requeued: {task_data}")
            else:
                logger.warning("No task processor set")
                ch.basic_ack(delivery_tag=method.delivery_tag)
                
        except json.JSONDecodeError as e:
            logger.error(f"Invalid JSON message: {e}")
            ch.basic_ack(delivery_tag=method.delivery_tag)  # Discard invalid messages
        except Exception as e:
            logger.error(f"Error processing task: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
    
    def start_consuming(self):
        logger.info(f"Starting to consume messages from '{self.queue_name}'")
        self.rabbitmq.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self._callback,
            auto_ack=False  # Manual acknowledgment
        )
        
        try:
            self.rabbitmq.channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Stopping consumer...")
            self.rabbitmq.channel.stop_consuming()
        except Exception as e:
            logger.error(f"Consumer error: {e}")
        finally:
            self.close()
    
    def close(self):
        self.rabbitmq.close()


